/* ============================================================
 * Low-Level UART Driver
 * ============================================================ */

static void uart_init(void)
{
    uint32_t brr_value;

    /* Enable GPIOA clock */
    REG32(RCC_BASE + RCC_AHB1ENR_OFFSET) |= RCC_AHB1ENR_GPIOAEN;

    /* Enable USART2 clock */
    REG32(RCC_BASE + RCC_APB1ENR_OFFSET) |= RCC_APB1ENR_USART2EN;

    /* Configure PA2 (TX) and PA3 (RX) as alternate function (AF7 = USART2) */
    /* PA2: MODER = AF (0b10) */
    REG32(GPIOA_BASE + GPIO_MODER_OFFSET) &= ~(3U << (2 * 2));
    REG32(GPIOA_BASE + GPIO_MODER_OFFSET) |=  (2U << (2 * 2));

    /* PA3: MODER = AF (0b10) */
    REG32(GPIOA_BASE + GPIO_MODER_OFFSET) &= ~(3U << (3 * 2));
    REG32(GPIOA_BASE + GPIO_MODER_OFFSET) |=  (2U << (3 * 2));

    /* Set AF7 for PA2 and PA3 (AFRL register, pins 0-7) */
    REG32(GPIOA_BASE + GPIO_AFRL_OFFSET) &= ~(0xFU << (2 * 4));
    REG32(GPIOA_BASE + GPIO_AFRL_OFFSET) |=  (7U << (2 * 4));
    REG32(GPIOA_BASE + GPIO_AFRL_OFFSET) &= ~(0xFU << (3 * 4));
    REG32(GPIOA_BASE + GPIO_AFRL_OFFSET) |=  (7U << (3 * 4));

    /* Disable UART before configuration */
    REG32(DIAG_UART_BASE + UART_CR1_OFFSET) = 0;

    /* Configure baud rate */
    brr_value = (APB1_CLOCK + (DIAG_UART_BAUD / 2)) / DIAG_UART_BAUD;
    REG32(DIAG_UART_BASE + UART_BRR_OFFSET) = brr_value;

    /* 8N1 configuration (default), enable TX, RX, and RXNE interrupt */
    REG32(DIAG_UART_BASE + UART_CR1_OFFSET) = UART_CR1_UE | UART_CR1_TE |
                                                UART_CR1_RE | UART_CR1_RXNEIE;

    /* Enable USART2 interrupt in NVIC */
    REG32(NVIC_ISER_BASE + (DIAG_UART_IRQn / 32) * 4) = (1U << (DIAG_UART_IRQn % 32));
}

static void uart_send_char(char c)
{
    while (!(REG32(DIAG_UART_BASE + UART_SR_OFFSET) & UART_SR_TXE)) {
        /* Wait for transmit buffer empty */
    }
    REG32(DIAG_UART_BASE + UART_DR_OFFSET) = (uint32_t)c;
}

static void uart_send_string(const char *str)
{
    if (str == NULL) return;
    while (*str) {
        if (*str == '\n') {
            uart_send_char('\r');
        }
        uart_send_char(*str++);
    }
}

static void uart_send_newline(void)
{
    uart_send_char('\r');
    uart_send_char('\n');
}

static const char hex_chars[] = "0123456789ABCDEF";

static void uart_send_hex8(uint8_t value)
{
    uart_send_char(hex_chars[(value >> 4) & 0x0F]);
    uart_send_char(hex_chars[value & 0x0F]);
}

static void uart_send_hex(uint32_t value, uint8_t digits)
{
    uart_send_string("0x");
    for (int i = (digits - 1) * 4; i >= 0; i -= 4) {
        uart_send_char(hex_chars[(value >> i) & 0x0F]);
    }
}

static void uart_send_uint32(uint32_t value)
{
    char buf[12];
    int i = 0;

    if (value == 0) {
        uart_send_char('0');
        return;
    }

    while (value > 0 && i < 10) {
        buf[i++] = '0' + (value % 10);
        value /= 10;
    }

    while (--i >= 0) {
        uart_send_char(buf[i]);
    }
}

/* USART2 IRQ Handler */
void USART2_IRQHandler(void)
{
    uint32_t sr = REG32(DIAG_UART_BASE + UART_SR_OFFSET);

    if (sr & UART_SR_ORE) {
        /* Clear overrun by reading DR */
        (void)REG32(DIAG_UART_BASE + UART_DR_OFFSET);
        return;
    }

    if (sr & UART_SR_RXNE) {
        char c = (char)(REG32(DIAG_UART_BASE + UART_DR_OFFSET) & 0xFF);

        if (g_cmd_buf.ready) {
            return;  /* Previous command not yet processed */
        }

        if (c == '\r' || c == '\n') {
            if (g_cmd_buf.pos > 0) {
                g_cmd_buf.buffer[g_cmd_buf.pos] = '\0';
                g_cmd_buf.ready = true;
                uart_send_newline();
            }
        } else if (c == '\b' || c == 0x7F) {
            /* Backspace */
            if (g_cmd_buf.pos > 0) {
                g_cmd_buf.pos--;
                uart_send_string("\b \b");
            }
        } else if (c == 0x03) {
            /* Ctrl+C - cancel current input */
            g_cmd_buf.pos = 0;
            uart_send_string("^C\n");
            uart_send_string("diag> ");
        } else if (c >= 0x20 && c < 0x7F) {
            if (g_cmd_buf.pos < CMD_BUFFER_SIZE - 1) {
                g_cmd_buf.buffer[g_cmd_buf.pos++] = c;
                uart_send_char(c);  /* Echo */
            }
        }
    }
}

