void SysTick_Handler(void)
{
    g_systick_ms++;
}

static void systick_init(void)
{
    /* Configure SysTick for 1ms ticks */
    volatile uint32_t *stk_load = (volatile uint32_t *)0xE000E014;
    volatile uint32_t *stk_ctrl = (volatile uint32_t *)0xE000E010;

    *stk_load = (SYSTEM_CORE_CLOCK / 1000) - 1;
    *stk_ctrl = 0x07;  /* Enable, interrupt, use processor clock */
}

/*
 * Simple hash function for token verification.
 * NOTE: In production, replace with proper HMAC-SHA256 or use
 * a secure element for authentication.
 */
static uint32_t simple_hash(const char *str)
{
    uint32_t hash = 0x811C9DC5;  /* FNV-1a offset basis */
    while (*str) {
        hash ^= (uint8_t)*str++;
        hash *= 0x01000193;  /* FNV-1a prime */
    }
    return hash;
}

static bool is_region_safe(uint32_t addr, uint32_t length)
{
#if RESTRICT_MEMORY_REGIONS
    uint32_t end_addr = addr + length;

    /* Check for overflow */
    if (end_addr < addr) return false;

    for (int i = 0; g_safe_regions[i].name != NULL; i++) {
        if (g_safe_regions[i].readable &&
            addr >= g_safe_regions[i].start &&
            end_addr <= g_safe_regions[i].end + 1) {
            return true;
        }
    }
    return false;
#else
    (void)addr;
    (void)length;
    return true;
#endif
}

static void audit_log(const char *cmd, diag_error_t result)
{
#if ENABLE_AUDIT_LOG
    audit_entry_t *entry = &g_audit_log[g_audit_index % AUDIT_LOG_ENTRIES];
    entry->timestamp = get_timestamp_seconds();
    strncpy(entry->command, cmd, sizeof(entry->command) - 1);
    entry->command[sizeof(entry->command) - 1] = '\0';
    entry->level = g_session.level;
    entry->result = result;
    g_audit_index++;
#else
    (void)cmd;
    (void)result;
#endif
}

static void check_session_timeout(void)
{
    if (!g_session.authenticated) return;

    uint32_t now = get_timestamp_seconds();
    if ((now - g_session.last_activity) > SESSION_TIMEOUT_SECONDS) {
        g_session.authenticated = false;
        g_session.level = AUTH_LEVEL_NONE;
        uart_send_string("\n[SESSION EXPIRED - Please re-authenticate]\n");
    }
}

static uint32_t parse_hex_or_dec(const char *str)
{
    uint32_t value = 0;

    if (str[0] == '0' && (str[1] == 'x' || str[1] == 'X')) {
        /* Hex */
        str += 2;
        while (*str) {
            char c = *str++;
            value <<= 4;
            if (c >= '0' && c <= '9') value |= (c - '0');
            else if (c >= 'a' && c <= 'f') value |= (c - 'a' + 10);
            else if (c >= 'A' && c <= 'F') value |= (c - 'A' + 10);
            else break;
        }
    } else {
        /* Decimal */
        while (*str >= '0' && *str <= '9') {
            value = value * 10 + (*str++ - '0');
        }
    }

    return value;
}

/* ============================================================
 * JTAG / SWD Configuration
 * ============================================================ */

static void jtag_pins_configure(bool enable)
{
    if (enable) {
        /*
         * SECURITY NOTE: Enabling JTAG on a production device allows:
         * - Full memory read/write access
         * - Firmware extraction
         * - Debug/halt of the processor
         * - Bypass of all software security measures
         * 
         * This should ONLY be done by authorized service personnel
         * and JTAG should be disabled when service is complete.
         */

        /* Configure PA13 (SWDIO) and PA14 (SWCLK) as AF0 (SWD) */
        REG32(GPIOA_BASE + GPIO_MODER_OFFSET) &= ~(3U << (13 * 2));
        REG32(GPIOA_BASE + GPIO_MODER_OFFSET) |=  (2U << (13 * 2));  /* AF */
        REG32(GPIOA_BASE + GPIO_MODER_OFFSET) &= ~(3U << (14 * 2));
        REG32(GPIOA_BASE + GPIO_MODER_OFFSET) |=  (2U << (14 * 2));  /* AF */

        /* AFRH for pins 13 and 14: AF0 (system) */
        REG32(GPIOA_BASE + GPIO_AFRH_OFFSET) &= ~(0xFU << ((13 - 8) * 4));
        REG32(GPIOA_BASE + GPIO_AFRH_OFFSET) &= ~(0xFU << ((14 - 8) * 4));

        /* Optional: Enable full JTAG (PA15=JTDI, PB3=JTDO, PB4=NJTRST) */
        /* REG32(GPIOA_BASE + GPIO_MODER_OFFSET) &= ~(3U << (15 * 2)); */
        /* REG32(GPIOA_BASE + GPIO_MODER_OFFSET) |=  (2U << (15 * 2)); */

        /* Enable trace in debug MCU */
        REG32(DBGMCU_BASE + DBGMCU_CR_OFFSET) |= DBGMCU_CR_TRACE_EN;

        g_jtag_enabled = true;
        uart_send_string("[WARNING] JTAG/SWD interface ENABLED\n");
        uart_send_string("[WARNING] Device security is reduced\n");
    } else {
        /* Reconfigure JTAG pins as GPIO (disabled) */
        /* PA13: Set as input (reset state will reassert SWD on next boot) */
        REG32(GPIOA_BASE + GPIO_MODER_OFFSET) &= ~(3U << (13 * 2));  /* Input */
        REG32(GPIOA_BASE + GPIO_MODER_OFFSET) &= ~(3U << (14 * 2));  /* Input */

        /* Disable trace */
        REG32(DBGMCU_BASE + DBGMCU_CR_OFFSET) &= ~DBGMCU_CR_TRACE_EN;

        g_jtag_enabled = false;
        uart_send_string("[INFO] JTAG/SWD interface DISABLED\n");
        uart_send_string("[INFO] Full disable effective after reboot\n");
    }
}

