static diag_error_t cmd_help(int argc, char *argv[])
{
    (void)argc;
    (void)argv;

    uart_send_string("\n=== Diagnostic Console Commands ===\n");
    uart_send_string("Auth Level: ");

    switch (g_session.level) {
        case AUTH_LEVEL_NONE:       uart_send_string("NONE"); break;
        case AUTH_LEVEL_BASIC:      uart_send_string("BASIC"); break;
        case AUTH_LEVEL_TECHNICIAN: uart_send_string("TECHNICIAN"); break;
        case AUTH_LEVEL_ENGINEER:   uart_send_string("ENGINEER"); break;
        default:                    uart_send_string("UNKNOWN"); break;
    }
    uart_send_newline();
    uart_send_string("------------------------------------\n");

    for (int i = 0; g_commands[i].name != NULL; i++) {
        const cmd_entry_t *cmd = &g_commands[i];

        /* Only show commands the user has access to */
        if (cmd->min_level <= g_session.level) {
#if PRODUCTION_LOCKED
            if (!cmd->allowed_in_production) continue;
#endif
            uart_send_string("  ");
            uart_send_string(cmd->name);

            /* Pad to column 18 */
            int pad = 18 - (int)strlen(cmd->name);
            while (pad-- > 0) uart_send_char(' ');

            uart_send_string("- ");
            uart_send_string(cmd->help);
            uart_send_newline();
        }
    }

    uart_send_string("------------------------------------\n");
    return DIAG_OK;
}

static diag_error_t cmd_login(int argc, char *argv[])
{
    uint32_t now = get_timestamp_seconds();

    /* Check lockout */
    if (g_session.lockout_until > now) {
        uart_send_string("[LOCKED] Too many failed attempts. Wait ");
        uart_send_uint32(g_session.lockout_until - now);
        uart_send_string(" seconds.\n");
        return DIAG_ERR_AUTH;
    }

    if (argc < 3) {
        uart_send_string("Usage: login <level> <token>\n");
        uart_send_string("  Levels: basic, tech, engineer\n");
        return DIAG_ERR_INVALID_ARG;
    }

    auth_level_t requested_level = AUTH_LEVEL_NONE;

    if (strcmp(argv[1], "basic") == 0)         requested_level = AUTH_LEVEL_BASIC;
    else if (strcmp(argv[1], "tech") == 0)     requested_level = AUTH_LEVEL_TECHNICIAN;
    else if (strcmp(argv[1], "engineer") == 0) requested_level = AUTH_LEVEL_ENGINEER;
    else {
        uart_send_string("[ERROR] Unknown level: ");
        uart_send_string(argv[1]);
        uart_send_newline();
        return DIAG_ERR_INVALID_ARG;
    }

    /* Hash the provided token and compare */
    uint32_t token_hash = simple_hash(argv[2]);

    /*
     * SECURITY NOTE: In production firmware, this should use:
     * 1. Challenge-response protocol (not static tokens)
     * 2. Time-limited tokens generated by a service tool
     * 3. Secure element for key storage and comparison
     * 4. Rate limiting and permanent lockout after excessive failures
     */

    if (token_hash == g_auth_tokens[requested_level]) {
        g_session.authenticated = true;
        g_session.level = requested_level;
        g_session.login_time = now;
        g_session.last_activity = now;
        g_session.failed_attempts = 0;

        uart_send_string("[OK] Authenticated at level: ");
        uart_send_string(argv[1]);
        uart_send_string("\n[INFO] Session timeout: ");
        uart_send_uint32(SESSION_TIMEOUT_SECONDS);
        uart_send_string(" seconds\n");

        return DIAG_OK;
    } else {
        g_session.failed_attempts++;
        uart_send_string("[FAILED] Authentication failed (attempt ");
        uart_send_uint32(g_session.failed_attempts);
        uart_send_char('/');
        uart_send_uint32(MAX_AUTH_ATTEMPTS);
        uart_send_string(")\n");

        if (g_session.failed_attempts >= MAX_AUTH_ATTEMPTS) {
            g_session.lockout_until = now + AUTH_LOCKOUT_SECONDS;
            uart_send_string("[LOCKED] Account locked for ");
            uart_send_uint32(AUTH_LOCKOUT_SECONDS);
            uart_send_string(" seconds\n");
        }

        return DIAG_ERR_AUTH;
    }
}

