static diag_error_t cmd_dump_memory(int argc, char *argv[])
{
#if PRODUCTION_LOCKED
    uart_send_string("[DENIED] Memory dump disabled in production-locked firmware\n");
    return DIAG_ERR_LOCKED;
#else

    if (argc < 3) {
        uart_send_string("Usage: dump_memory <address> <length>\n");
        uart_send_string("  address: hex (0x...) or decimal\n");
        uart_send_string("  length:  bytes to read (max 256)\n");
        return DIAG_ERR_INVALID_ARG;
    }

    uint32_t addr = parse_hex_or_dec(argv[1]);
    uint32_t length = parse_hex_or_dec(argv[2]);

    /* Safety limits */
    if (length == 0 || length > 256) {
        uart_send_string("[ERROR] Length must be 1-256 bytes\n");
        return DIAG_ERR_INVALID_ARG;
    }

    /* Alignment */
    addr &= ~3U;  /* Word-align */

    /* Region safety check */
    if (!is_region_safe(addr, length)) {
        uart_send_string("[DENIED] Address range not in permitted regions\n");
        uart_send_string("Use 'regions' command to see allowed memory ranges\n");
        return DIAG_ERR_OUT_OF_RANGE;
    }

    uart_send_string("\nMemory dump at ");
    uart_send_hex(addr, 8);
    uart_send_string(", length ");
    uart_send_uint32(length);
    uart_send_string(" bytes:\n");
    uart_send_string("Address    | 00 01 02 03 04 05 06 07 08 09 0A 0B 0C 0D 0E 0F | ASCII\n");
    uart_send_string("-----------+--------------------------------------------------+-----------------\n");

    for (uint32_t offset = 0; offset < length; offset += 16) {
        uint32_t line_addr = addr + offset;
        uint32_t line_len = (length - offset) < 16 ? (length - offset) : 16;

        /* Address column */
        uart_send_hex(line_addr, 8);
        uart_send_string(" | ");

        /* Hex bytes */
        for (uint32_t i = 0; i < 16; i++) {
            if (i < line_len) {
                uint8_t byte = *((volatile uint8_t *)(line_addr + i));
                uart_send_hex8(byte);
                uart_send_char(' ');
            } else {
                uart_send_string("   ");
            }
        }

        uart_send_string("| ");

        /* ASCII representation */
        for (uint32_t i = 0; i < line_len; i++) {
            uint8_t byte = *((volatile uint8_t *)(line_addr + i));
            if (byte >= 0x20 && byte < 0x7F) {
                uart_send_char((char)byte);
            } else {
                uart_send_char('.');
            }
        }

        uart_send_newline();
    }

    return DIAG_OK;
#endif
}

static diag_error_t cmd_read_flash(int argc, char *argv[])
{
#if PRODUCTION_LOCKED
    uart_send_string("[DENIED] Flash read disabled in production-locked firmware\n");
    return DIAG_ERR_LOCKED;
#else

    if (argc < 2) {
        uart_send_string("Usage: read_flash <offset> [length]\n");
        uart_send_string("  offset: byte offset from flash base (");
        uart_send_hex(FLASH_BASE_ADDR, 8);
        uart_send_string(")\n");
        uart_send_string("  length: bytes to read (max 256, default 64)\n");
        return DIAG_ERR_INVALID_ARG;
    }

    uint32_t offset = parse_hex_or_dec(argv[1]);
    uint32_t length = (argc > 2) ? parse_hex_or_dec(argv[2]) : 64;

    if (length > 256) {
        uart_send_string("[ERROR] Max read length is 256 bytes\n");
        return DIAG_ERR_INVALID_ARG;
    }

    if (offset + length > FLASH_SIZE) {
        uart_send_string("[ERROR] Offset + length exceeds flash size\n");
        return DIAG_ERR_OUT_OF_RANGE;
    }

    uint32_t flash_addr = FLASH_BASE_ADDR + offset;

    uart_send_string("\nFlash read at offset ");
    uart_send_hex(offset, 8);
    uart_send_string(" (addr ");
    uart_send_hex(flash_addr, 8);
    uart_send_string("):\n");

    /* Reuse memory dump format */
    char *args[3];
    char addr_str[12];
    char len_str[12];

    /* Format address as hex string */
    int idx = 0;
    addr_str[idx++] = '0';
    addr_str[idx++] = 'x';
    for (int i = 28; i >= 0; i -= 4) {
        addr_str[idx++] = hex_chars[(flash_addr >> i) & 0xF];
    }
    addr_str[idx] = '\0';

    idx = 0;
    len_str[idx++] = '0';
    len_str[idx++] = 'x';
    for (int i = 28; i >= 0; i -= 4) {
        len_str[idx++] = hex_chars[(length >> i) & 0xF];
    }
    len_str[idx] = '\0';

    args[0] = (char *)"dump_memory";
    args[1] = addr_str;
    args[2] = len_str;

    return cmd_dump_memory(3, args);
#endif
}

