static diag_error_t cmd_gpio_read(int argc, char *argv[])
{
    if (argc < 3) {
        uart_send_string("Usage: gpio_read <port:A-E> <pin:0-15>\n");
        return DIAG_ERR_INVALID_ARG;
    }

    char port = argv[1][0];
    uint32_t pin = parse_hex_or_dec(argv[2]);

    if ((port < 'A' || port > 'E') && (port < 'a' || port > 'e')) {
        uart_send_string("[ERROR] Invalid port (use A-E)\n");
        return DIAG_ERR_INVALID_ARG;
    }
    if (pin > 15) {
        uart_send_string("[ERROR] Invalid pin (use 0-15)\n");
        return DIAG_ERR_INVALID_ARG;
    }

    /* Calculate GPIO base address */
    uint32_t port_index = (port >= 'a') ? (port - 'a') : (port - 'A');
    uint32_t gpio_base = 0x40020000 + (port_index * 0x400);

    /* Read IDR (Input Data Register, offset 0x10) */
    uint32_t idr = REG32(gpio_base + 0x10);
    uint32_t value = (idr >> pin) & 1;

    /* Read MODER */
    uint32_t moder = REG32(gpio_base + 0x00);
    uint32_t mode = (moder >> (pin * 2)) & 3;

    uart_send_string("GPIO");
    uart_send_char(port >= 'a' ? (port - 32) : port);
    uart_send_uint32(pin);
    uart_send_string(": Value=");
    uart_send_uint32(value);
    uart_send_string(", Mode=");
    switch (mode) {
        case 0: uart_send_string("INPUT");  break;
        case 1: uart_send_string("OUTPUT"); break;
        case 2: uart_send_string("AF");     break;
        case 3: uart_send_string("ANALOG"); break;
    }
    uart_send_newline();

    return DIAG_OK;
}

