static diag_error_t cmd_reboot(int argc, char *argv[])
{
    (void)argc;
    (void)argv;

    /* Disable JTAG before reboot */
    if (g_jtag_enabled) {
        jtag_pins_configure(false);
    }

    uart_send_string("[INFO] Rebooting device...\n");

    /* Small delay to allow UART to flush */
    for (volatile uint32_t i = 0; i < 1000000; i++);

    /* Trigger system reset via AIRCR */
    volatile uint32_t *aircr = (volatile uint32_t *)0xE000ED0C;
    *aircr = (0x5FA << 16) | (1 << 2);  /* SYSRESETREQ */

    /* Should not reach here */
    while (1);

    return DIAG_OK;
}

