/* ============================================================
 * Command Parser and Dispatcher
 * ============================================================ */

static int parse_args(char *cmd_line, char *argv[], int max_args)
{
    int argc = 0;
    bool in_arg = false;

    while (*cmd_line && argc < max_args) {
        if (*cmd_line == ' ' || *cmd_line == '\t') {
            *cmd_line = '\0';
            in_arg = false;
        } else if (!in_arg) {
            argv[argc++] = cmd_line;
            in_arg = true;
        }
        cmd_line++;
    }

    return argc;
}

static void dispatch_command(char *cmd_line)
{
    char *argv[MAX_ARGS];
    int argc;
    char cmd_copy[CMD_BUFFER_SIZE];

    /* Preserve command for audit logging */
    strncpy(cmd_copy, cmd_line, sizeof(cmd_copy) - 1);
    cmd_copy[sizeof(cmd_copy) - 1] = '\0';

    argc = parse_args(cmd_line, argv, MAX_ARGS);

    if (argc == 0) return;

    /* Check session timeout before processing */
    check_session_timeout();

    /* Find and execute command */
    for (int i = 0; g_commands[i].name != NULL; i++) {
        if (strcmp(argv[0], g_commands[i].name) == 0) {
            const cmd_entry_t *cmd = &g_commands[i];

#if PRODUCTION_LOCKED
            if (!cmd->allowed_in_production) {
                uart_send_string("[DENIED] Command not available in production-locked mode\n");
                audit_log(cmd_copy, DIAG_ERR_LOCKED);
                return;
            }
#endif

            /* Check authorization level */
            if (g_session.level < cmd->min_level) {
                uart_send_string("[DENIED] Insufficient privileges (need level ");
                uart_send_uint32((uint32_t)cmd->min_level);
                uart_send_string(", have ");
                uart_send_uint32((uint32_t)g_session.level);
                uart_send_string(")\n");
                audit_log(cmd_copy, DIAG_ERR_AUTH);
                return;
            }

            /* Update session activity */
            g_session.last_activity = get_timestamp_seconds();

            /* Execute command */
            diag_error_t result = cmd->handler(argc, argv);
            audit_log(cmd_copy, result);
            return;
        }
    }

    uart_send_string("[ERROR] Unknown command: '");
    uart_send_string(argv[0]);
    uart_send_string("'. Type 'help' for available commands.\n");
    audit_log(cmd_copy, DIAG_ERR_INVALID_CMD);
}

